func testAccApihubRuntimeProjectAttachment_apihubRuntimeProjectAttachmentBasicExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_project" "host_project" {
    name       = "h-%{project_id}"
    project_id = "h-%{project_id}"
    org_id     = "%{org_id}"
    billing_account = "%{billing_account}"
    deletion_policy = "DELETE"
}

resource "time_sleep" "wait_60_seconds" {
    create_duration = "60s"
    depends_on = [google_project.host_project]
}

# Enable API hub API on host project
resource "google_project_service" "apihub_service" {
    project = google_project.host_project.project_id
    service = "apihub.googleapis.com"
    depends_on = [time_sleep.wait_60_seconds]
}

resource "google_apihub_host_project_registration" "host_project_reg" {
    project = google_project.host_project.project_id
    location = "asia-south1"
    host_project_registration_id = google_project.host_project.project_id
    gcp_project = "projects/${google_project.host_project.project_id}"

    depends_on = [google_project_service.apihub_service]
}

resource "google_project" "runtime_project" {
    name       = "r-%{project_id}"
    project_id = "r-%{project_id}"
    org_id     = "%{org_id}"
    billing_account = "%{billing_account}"
    deletion_policy = "DELETE"
}

# Enable API hub API on runtime project
resource "google_project_service" "apihub_service_runtime" {
    project = google_project.runtime_project.project_id
    service = "apihub.googleapis.com"
    depends_on = [time_sleep.wait_60_seconds]
}

resource "google_apihub_runtime_project_attachment" "apihub_runtime_project_attachment" {
    project = google_project.host_project.project_id
    location = "asia-south1"
    runtime_project_attachment_id = google_project.runtime_project.project_id
    runtime_project = "projects/${google_project.runtime_project.project_id}"

    depends_on = [
        google_apihub_host_project_registration.host_project_reg,
        google_project_service.apihub_service_runtime
    ]
}
`, context)
}

func testAccCheckApihubRuntimeProjectAttachmentDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_apihub_runtime_project_attachment" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(apihub.Product, config)+"projects/{{project}}/locations/{{location}}/runtimeProjectAttachments/{{runtime_project_attachment_id}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("ApihubRuntimeProjectAttachment still exists at %s", url)
			}
		}

		return nil
	}
}
